package shell.org.apache.accumulo.shell.commands;

public class FormatterCommand extends ShellPluginConfigurationCommand { private Option interpeterOption ; public FormatterCommand ( ) { super ( "formatter" , Property . TABLE_FORMATTER_CLASS , "f" ) ; } @ Override public String description ( ) { return "specifies a formatter to use for displaying table entries" ; } public static Class < ? extends Formatter > getCurrentFormatter ( final String tableName , final Shell shellState ) { return ShellPluginConfigurationCommand . getPluginClass ( tableName , shellState , Formatter . class , Property . TABLE_FORMATTER_CLASS ) ; } @ Override public Options getOptions ( ) { final Options options = super . getOptions ( ) ; interpeterOption = new Option ( "i" , "interpeter" , false , "configure class as interpreter also" ) ; options . addOption ( interpeterOption ) ; return options ; } @ Override protected void setPlugin ( final CommandLine cl , final Shell shellState , final String tableName , final String className ) throws AccumuloException , AccumuloSecurityException { super . setPlugin ( cl , shellState , tableName , className ) ; if ( cl . hasOption ( interpeterOption . getOpt ( ) ) ) { shellState . getConnector ( ) . tableOperations ( ) . setProperty ( tableName , Property . TABLE_INTERPRETER_CLASS . toString ( ) , className ) ; } } @ Override protected void removePlugin ( final CommandLine cl , final Shell shellState , final String tableName ) throws AccumuloException , AccumuloSecurityException { super . removePlugin ( cl , shellState , tableName ) ; if ( cl . hasOption ( interpeterOption . getOpt ( ) ) ) { shellState . getConnector ( ) . tableOperations ( ) . removeProperty ( tableName , Property . TABLE_INTERPRETER_CLASS . toString ( ) ) ; } } }